select
    f.fee_id, f.fee_code, f.fee_amount, f.invoice_amount, f.payment_amount, f.payment_date, f.fee_type, f.status,
    f.fee_desc, f.create_time, f.update_time,
    f.ent_code, e.ent_name,
    f.project_id, p.project_code, p.project_name
from t_env_fees f
left join t_bas_enterprise e on e.ent_code = f.ent_code
left join t_env_mange_project p on p.project_id = f.project_id



            and f.ent_code = #{entCode}



                and f.ent_code in

                    #{entCode}





        and f.project_id = #{projectId}


        and f.fee_type = #{feeType}


        and f.payment_date between #{paymentStart} and #{paymentEnd}


        and f.status = #{status}


order by f.fee_id desc

